function D(t,e="INR"){return new Intl.NumberFormat("en-IN",{style:"currency",currency:e,maximumFractionDigits:2}).format(Number(t||0))}function y(t){if(!t)return"-";const e=new Date(t);return Number.isNaN(e.getTime())?t:e.toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"})}function w(t){if(!t)return"-";const e=new Date(t);return Number.isNaN(e.getTime())?t:e.toLocaleString("en-IN",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"})}function m(){const t=new Date,e=String(t.getMonth()+1).padStart(2,"0");return`${t.getFullYear()}-${e}`}const l="all",N=/^\d{4}-(0[1-9]|1[0-2])$/;function S(t){return String(t||"").toLowerCase()===l}function d(t){return N.test(String(t||""))}function b(){const t=new Date;return new Date(t.getTime()-t.getTimezoneOffset()*6e4).toISOString().slice(0,16)}function h(t=12,e=m()){const[n,r]=String(e).split("-"),i=Number(n),s=Number(r);if(!i||!s)return[];const c=new Date(i,s-1,1),u=[];for(let o=0;o<t;o+=1){const a=new Date(c.getFullYear(),c.getMonth()-o,1),g=`${a.getFullYear()}-${String(a.getMonth()+1).padStart(2,"0")}`,f=a.toLocaleDateString("en-IN",{month:"short",year:"2-digit"});u.push({value:g,label:f})}return u}function p(t=12,e=m()){return[{value:l,label:"All"},...h(t,e)]}function M(t){if(S(t)||!d(t))return null;const[e,n]=String(t).split("-"),r=new Date(Number(e),Number(n),0).getDate();return{date_from:`${t}-01`,date_to:`${t}-${String(r).padStart(2,"0")}`}}export{y as a,w as b,m as c,b as d,M as e,D as f,S as i,p as m};
